INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('optician-moex-02699', 'optician', 'optician-moex-106-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '關於硬式透氣隱形眼鏡鏡片中的高透氧材料，下列敘述何者正確？', '["材料中添了氟，是由於氧氣無法溶解在氟化物中，所以促進氧氣快速穿透", "材料中添了矽，因此氧氣可藉由鏡片材料中的矽分子作傳遞", "矽含量的增加會提升材料的親水性和彈性，從而降低乾燥、沉澱的發生率", "含有矽的側鏈增加了聚合鏈之間的空隙，從而增加材料的透氧性"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:38+00:00", "source_pdf_sha1": "21dccecf40fb", "answer_pdf_sha1": "332b43e00546", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02700', 'optician', 'optician-moex-106-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '一患者可見的虹膜水平直徑（horizontal visible iris diameter, HVID）為11.5 mm，此患者選擇配戴軟式隱 形眼鏡，在實務上最合適的鏡片直徑為：', '["9.50 mm", "11.00 mm", "13.50 mm", "15.00 mm"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:38+00:00", "source_pdf_sha1": "21dccecf40fb", "answer_pdf_sha1": "332b43e00546", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02701', 'optician', 'optician-moex-106-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '戴硬式隱形眼鏡鏡片眨眼後，正常情況下，淚液的轉換量有多少？', '["100%", "90%", "10～20%", "1～2%"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:38+00:00", "source_pdf_sha1": "21dccecf40fb", "answer_pdf_sha1": "332b43e00546", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02702', 'optician', 'optician-moex-106-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '硬式透氣隱形眼鏡度數-4.00 DS，弧度7.70 mm，戴鏡驗光後的度數為-4.50 DS，若想把弧度改成7.60 mm， 則硬式透氣隱形眼鏡的度數應該改為幾度？', '["-8.00 DS", "-8.25 DS", "-8.75 DS", "-9.25 DS"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:38+00:00", "source_pdf_sha1": "21dccecf40fb", "answer_pdf_sha1": "332b43e00546", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02703', 'optician', 'optician-moex-106-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '當角膜弧度儀檢查和綜合驗光機檢查的順散光（with-the-rule astigmatism）讀值顯示相差1.5屈光度的差 異時，下列何者正確？', '["此差異值屬於角膜散光，適合配戴硬式散光隱形眼鏡矯正", "此差異比較有可能是水晶體散光，適合配戴軟式散光隱形眼鏡矯正", "順散光通常需要過度矯正", "存在差異時，通常表示綜合驗光機檢查出現錯誤"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:38+00:00", "source_pdf_sha1": "21dccecf40fb", "answer_pdf_sha1": "332b43e00546", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02704', 'optician', 'optician-moex-106-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '下列何者不是圓錐角膜患者配戴硬式隱形眼鏡，較適合的螢光染劑型態？', '["頂點接觸形（apical bearing）", "三點接觸形（three-point touch）", "頂點淨空形（apical clearance）", "啞鈴形（dumbbell-shaped）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:38+00:00", "source_pdf_sha1": "21dccecf40fb", "answer_pdf_sha1": "332b43e00546", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02705', 'optician', 'optician-moex-106-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '關於隱形眼鏡驗配，下列敘述何者錯誤？', '["軟式鏡片的理想配適，眨眼時有0.5毫米左右的滑動，表示配適沒有過緊", "硬式鏡片的理想配適，眨眼時有1.0至2.0毫米的滑動，但若移動距離超過眼輪部，則配適可能過鬆", "鞏膜鏡片的理想配適，眨眼時有至少2.0毫米的滑動，才能保證足夠的淚液交換", "要判斷鏡片是否過緊，可嘗試在鏡片下緣輕輕往上推（push-up test），若推不動鏡片表示配適過緊"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:38+00:00", "source_pdf_sha1": "21dccecf40fb", "answer_pdf_sha1": "332b43e00546", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02706', 'optician', 'optician-moex-106-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '關於硬式隱形眼鏡基弧的選擇，可藉由觀察動態滑動與靜態螢光染色做調整，若患者目前配戴基弧', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:38+00:00", "source_pdf_sha1": "21dccecf40fb", "answer_pdf_sha1": "332b43e00546", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 32, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02707', 'optician', 'optician-moex-106-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '40毫米的硬式鏡片試片，則下列鏡片調整何者錯誤？', '["動態滑動過大，表示鏡片太鬆，可改用基弧為7.20毫米試片", "動態滑動過小，表示鏡片太緊，可改用基弧為7.60毫米試片", "靜態螢光染色顯現中央光學區有過多淚液淤積，可改用基弧為7.60毫米試片", "靜態螢光染色顯現鏡片周邊區有過寬的淚液淤積，可改用基弧為7.60毫米試片"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:38+00:00", "source_pdf_sha1": "21dccecf40fb", "answer_pdf_sha1": "332b43e00546", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02708', 'optician', 'optician-moex-106-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '角膜平均屈光度為44屈光度，角膜散光接近0屈光度；以不同基弧的硬式鏡片試戴後進行電腦驗光。假 設鏡片其他參數相同，患者配戴那一個鏡片的殘餘近視度數可能最多？', '["基弧7.2毫米的鏡片", "基弧7.5毫米的鏡片", "基弧7.7毫米的鏡片", "基弧8.0毫米的鏡片"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:38+00:00", "source_pdf_sha1": "21dccecf40fb", "answer_pdf_sha1": "332b43e00546", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL)
